DROP DATABASE IF EXISTS `substore`;
CREATE DATABASE `substore` CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE `substore`;

CREATE TABLE `categories` (
  `name` VARCHAR(100) NOT NULL,
  `description` TEXT NOT NULL,
  `icon` VARCHAR(100) NOT NULL,
  `gradient` VARCHAR(100) NOT NULL,
  PRIMARY KEY (`name`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE `products` (
  `id` VARCHAR(100) NOT NULL,
  `slug` VARCHAR(100) NOT NULL,
  `name` VARCHAR(255) NOT NULL,
  `brand` VARCHAR(100) NOT NULL,
  `brandColor` VARCHAR(100) NOT NULL,
  `category` VARCHAR(100) NOT NULL,
  `platform` VARCHAR(100) NOT NULL,
  `region` VARCHAR(100) NOT NULL,
  `duration` VARCHAR(100) NOT NULL,
  `price` DECIMAL(8,2) NOT NULL,
  `originalPrice` DECIMAL(8,2) NOT NULL,
  `rating` DECIMAL(3,1) NOT NULL,
  `reviews` INT NOT NULL,
  `sold` INT NOT NULL,
  `stock` INT NOT NULL,
  `instant` TINYINT(1) NOT NULL,
  `featured` TINYINT(1) NOT NULL,
  `bestSeller` TINYINT(1) NOT NULL,
  `newArrival` TINYINT(1) NOT NULL,
  `flashDeal` TINYINT(1) NOT NULL,
  `flashEndsAt` BIGINT NULL,
  `description` TEXT NOT NULL,
  `includes` TEXT NOT NULL,
  `activation` TEXT NOT NULL,
  `faqs` TEXT NOT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_category` (`category`),
  CONSTRAINT `fk_products_category` FOREIGN KEY (`category`) REFERENCES `categories` (`name`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE `reviews` (
  `id` INT NOT NULL AUTO_INCREMENT,
  `name` VARCHAR(100) NOT NULL,
  `country` VARCHAR(10) NOT NULL,
  `rating` INT NOT NULL,
  `text` TEXT NOT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE `users` (
  `id` INT NOT NULL AUTO_INCREMENT,
  `name` VARCHAR(120) NOT NULL,
  `email` VARCHAR(150) NOT NULL,
  `plan` VARCHAR(30) NOT NULL DEFAULT 'Starter',
  `orders` INT NOT NULL DEFAULT 0,
  `status` VARCHAR(20) NOT NULL DEFAULT 'Active',
  `joined_at` TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_users_email` (`email`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE `orders` (
  `id` INT NOT NULL AUTO_INCREMENT,
  `user_email` VARCHAR(150) NOT NULL,
  `user_name` VARCHAR(120) NOT NULL,
  `product_id` VARCHAR(100) NOT NULL,
  `product_name` VARCHAR(255) NOT NULL,
  `qty` INT NOT NULL DEFAULT 1,
  `price` DECIMAL(8,2) NOT NULL,
  `code` VARCHAR(255) NOT NULL,
  `status` VARCHAR(20) NOT NULL DEFAULT 'Delivered',
  `created_at` TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_user_email` (`user_email`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

